def extract_products_from_html_table(html_table: str, allowed_products: list) -> list:
    """
    Извлекает продукты, очищает от цифр и проверяет наличие в списке.
    Возвращает список продуктов в нижнем регистре.
    """
    found_products = []

    # Парсим HTML
    soup = BeautifulSoup(html_table, 'html.parser')
    rows = soup.find_all('tr')

    for row in rows:
        cells = row.find_all('td')
        if len(cells) >= 2:
            raw_name = cells[0].get_text().strip()

            # 1. Убираем цифры в начале (например "2 APPLE" -> "APPLE")
            product_name_clean = re.sub(r'^\d+\s+', '', raw_name).strip()

            # 2. Убираем множители в конце (например "Soap x1" -> "Soap")
            product_name_clean = re.sub(r'\s*x\d+', '', product_name_clean).strip()

            # 3. Проверяем наличие в списке (сравниваем в нижнем регистре)
            for allowed in allowed_products:
                if product_name_clean.lower() == allowed.lower():
                    # Если продукт уже есть в списке, не добавляем дубликат
                    if product_name_clean.lower() not in found_products:
                        # ДОБАВЛЯЕМ В НИЖНЕМ РЕГИСТРЕ
                        found_products.append(product_name_clean.lower())
                    break

    return found_products


